+    #[test]
+    fn df_apply_axis1_prod_skips_nulls_like_rowwise_product() {
+        let df = DataFrame::from_dict(
+            &["a", "b", "c"],
+            vec![
+                ("a", vec![Scalar::Float64(2.0), Scalar::Null(NullKind::NaN)]),
+                ("b", vec![Scalar::Float64(3.0), Scalar::Float64(4.0)]),
+                ("c", vec![Scalar::Float64(5.0), Scalar::Float64(6.0)]),
+            ],
+        )
+        .unwrap();
+
+        let prod = df.apply("prod", 1).unwrap();
+        let product = df.apply("product", 1).unwrap();
+        assert_eq!(prod.index().labels(), df.index().labels());
+        assert_eq!(prod.column().values(), product.column().values());
+
+        let first = expect_float64(&prod.column().values()[0]);
+        let second = expect_float64(&prod.column().values()[1]);
+        assert!((first - 30.0).abs() < 1e-12);
+        assert!((second - 24.0).abs() < 1e-12);
+    }
